const body = $input.first().json.body || $input.first().json;
const event_type = body.event_type || body.trigger || 'unknown';
const user_id = body.user_id || null;
const workspace_id = body.workspace_id || null;
const payload = body.payload || {};
const SUPPORTED = ['first_mission_completed', 'stalled_user', 'plan_upgraded', 'subscription_cancelled', 'onboarding_complete'];
if (!user_id) throw new Error('user_id is required');
if (!SUPPORTED.includes(event_type)) {
  return [{ json: { skipped: true, reason: `Unsupported event_type: ${event_type}` } }];
}
return [{ json: { event_type, user_id, workspace_id, payload, now: new Date().toISOString(), skipped: false } }];

const ctx = $('Parse & Validate').item.json;
const wsArr = $('Load Workspace').item.json;
const ws = Array.isArray(wsArr) ? wsArr[0] : wsArr;
const profArr = $('Load Profile').item.json;
const profile = Array.isArray(profArr) ? profArr[0] : profArr;
const FOLLOW_UP_COPY = {
  'first_mission_completed': {
    subject: 'Mission complete — what\'s next for you',
    preview: 'Your first mission is done. Here\'s how to keep the momentum going.',
    cta_label: 'See your next mission',
    cta_url: '/app/dashboard'
  },
  'stalled_user': {
    subject: 'Still thinking about your idea?',
    preview: 'You haven\'t run a tool in a while — let\'s unstick you in 5 minutes.',
    cta_label: 'Jump back in',
    cta_url: '/app/launchpad/idea-validator'
  },
  'plan_upgraded': {
    subject: 'You\'re on the upgraded plan — here\'s what unlocked',
    preview: 'Premium tools, higher limits, and full operator access are now live.',
    cta_label: 'Explore what\'s new',
    cta_url: '/app/dashboard'
  },
  'subscription_cancelled': {
    subject: 'Your subscription has been cancelled',
    preview: 'You can still access free tools. Here\'s what you\'ll have access to.',
    cta_label: 'See free tools',
    cta_url: '/app/launchpad'
  },
  'onboarding_complete': {
    subject: 'Your workspace is live — let\'s build',
    preview: 'Validate your first idea, build your offer, and map your go-to-market.',
    cta_label: 'Start with Idea Validator',
    cta_url: '/app/launchpad/idea-validator'
  }
};
const copy = FOLLOW_UP_COPY[ctx.event_type] || { subject: 'Update from Bylda', preview: '', cta_label: 'Open dashboard', cta_url: '/app/dashboard' };
return [{ json: { ...ctx, workspace: ws || null, lane: ws?.lane || 'Idea', profile: profile || null, copy } }];

